CREATE TABLE IF NOT EXISTS role( role_cd_id UUID PRIMARY KEY, role_tx_name TEXT UNIQUE NOT NULL );
INSERT INTO role(role_cd_id, role_tx_name) VALUES ('0a5982c8-baa4-4e66-8614-01cf35ad4cfc', 'DEV'), ('0b5982c8-baa4-4e66-8614-01cf35ad4cfc', 'ADM');
CREATE TABLE IF NOT EXISTS user_account( usac_cd_id UUID PRIMARY KEY, usac_tx_username TEXT UNIQUE NOT NULL, usac_tx_password TEXT NOT NULL, usac_nm_account_locked BOOLEAN NOT NULL DEFAULT FALSE, usac_nm_failed_login_attempts INTEGER DEFAULT 0, usac_dt_lock_until TIMESTAMP, usac_dt_last_login_at TIMESTAMP, usac_dt_created_at TIMESTAMP NOT NULL, usac_dt_updated_at TIMESTAMP );
CREATE TABLE user_role ( usac_cd_id UUID NOT NULL REFERENCES user_account(usac_cd_id) ON UPDATE NO ACTION ON DELETE CASCADE, role_cd_id UUID NOT NULL REFERENCES role(role_cd_id) ON UPDATE NO ACTION ON DELETE CASCADE );
